# Second Highest Number Function

Here are several approaches to find the second highest number in an array:

## Method 1: Using Sort (Simplest)
```javascript
function secondHighest(arr) {
  const sorted = [...arr].sort((a, b) => b - a);
  return sorted[1];
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Method 2: Using Math.max (Most Efficient)
```javascript
function secondHighest(arr) {
  const max = Math.max(...arr);
  const filtered = arr.filter(num => num !== max);
  return Math.max(...filtered);
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Method 3: Single Loop (Best for Large Arrays)
```javascript
function secondHighest(arr) {
  let max = -Infinity;
  let secondMax = -Infinity;

  for (let num of arr) {
    if (num > max) {
      secondMax = max;
      max = num;
    } else if (num > secondMax && num !== max) {
      secondMax = num;
    }
  }

  return secondMax;
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Method 4: Handling Duplicates
```javascript
function secondHighest(arr) {
  const unique = [...new Set(arr)].sort((a, b) => b - a);
  return unique[1];
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
console.log(secondHighest([31, 31, 15, 11]));  // Output: 15
```

## Comparison Table

| Method | Time | Space | Notes |
|--------|------|-------|-------|
| Sort | O(n log n) | O(n) | Simple, creates copy |
| Math.max | O(n) | O(n) | Good for small arrays |
| Single Loop | O(n) | O(1) | **Best overall** |
| Set + Sort | O(n log n) | O(n) | Handles duplicates |

## Recommendation
Use **Method 3** for production code—it's the most efficient with O(n) time complexity and O(1) space complexity.

# Find Second Highest Number

Here are a few different approaches:

## 1. **Using `sort()` (Simplest)**
```javascript
function secondHighest(arr) {
  const sorted = arr.sort((a, b) => b - a);
  return sorted[1];
}

console.log(secondHighest([11, 2, 31, 7, 15])); // 15
```

## 2. **Using `Set` to Remove Duplicates**
```javascript
function secondHighest(arr) {
  const unique = [...new Set(arr)].sort((a, b) => b - a);
  return unique[1];
}

console.log(secondHighest([11, 2, 31, 7, 15])); // 15
```

## 3. **Using `Math.max()` (Most Efficient)**
```javascript
function secondHighest(arr) {
  const max = Math.max(...arr);
  const filtered = arr.filter(num => num !== max);
  return Math.max(...filtered);
}

console.log(secondHighest([11, 2, 31, 7, 15])); // 15
```

## 4. **Using Reduce (Single Pass)**
```javascript
function secondHighest(arr) {
  let max = -Infinity, secondMax = -Infinity;

  for (let num of arr) {
    if (num > max) {
      secondMax = max;
      max = num;
    } else if (num > secondMax && num !== max) {
      secondMax = num;
    }
  }

  return secondMax;
}

console.log(secondHighest([11, 2, 31, 7, 15])); // 15
```

## **Comparison**

| Method | Pros | Cons |
|--------|------|------|
| `sort()` | Simple & readable | O(n log n) time, modifies original array |
| `Set + sort()` | Handles duplicates | O(n log n) time |
| `Math.max()` | O(n) time | Creates filtered array |
| `Reduce` | **Most efficient** O(n), single pass | Slightly more complex |

**Recommendation:** Use **Method 4 (Reduce)** for best performance with large arrays, or **Method 1** for simplicity and readability.

# Function to Find Second Highest Number

Here are several approaches:

## Approach 1: Simple and Readable
```javascript
function findSecondHighest(arr) {
  if (arr.length < 2) {
    return null; // Not enough elements
  }

  const sorted = arr.sort((a, b) => b - a);
  return sorted[1];
}

console.log(findSecondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Approach 2: Handle Duplicates (Remove Duplicates First)
```javascript
function findSecondHighest(arr) {
  const unique = [...new Set(arr)]; // Remove duplicates

  if (unique.length < 2) {
    return null;
  }

  unique.sort((a, b) => b - a);
  return unique[1];
}

console.log(findSecondHighest([11, 2, 31, 7, 15])); // Output: 15
console.log(findSecondHighest([31, 31, 15, 11, 7])); // Output: 15
```

## Approach 3: Most Efficient (O(n) time complexity)
```javascript
function findSecondHighest(arr) {
  if (arr.length < 2) {
    return null;
  }

  let highest = -Infinity;
  let secondHighest = -Infinity;

  for (let num of arr) {
    if (num > highest) {
      secondHighest = highest;
      highest = num;
    } else if (num > secondHighest && num !== highest) {
      secondHighest = num;
    }
  }

  return secondHighest === -Infinity ? null : secondHighest;
}

console.log(findSecondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Approach 4: Using Math.max (Concise)
```javascript
function findSecondHighest(arr) {
  const max = Math.max(...arr);
  const filtered = arr.filter(num => num < max);

  return filtered.length > 0 ? Math.max(...filtered) : null;
}

console.log(findSecondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Comparison Table

| Approach | Pros | Cons |
|----------|------|------|
| **Sorting** | Simple, readable | O(n log n) complexity |
| **Unique + Sort** | Handles duplicates | O(n log n) complexity |
| **Linear Scan** | Best performance O(n) | More code |
| **Math.max** | Very concise | Less efficient |

## Recommendation
Use **Approach 3** for best performance or **Approach 2** if you need to handle duplicate values properly.

# Find Second Highest Number in Array

Here are several approaches:

## 1. **Simple and Readable Approach** (Recommended)
```javascript
function secondHighest(arr) {
  // Remove duplicates and sort in descending order
  const unique = [...new Set(arr)].sort((a, b) => b - a);

  // Return second element if it exists
  return unique.length > 1 ? unique[1] : null;
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## 2. **Using Math.max() - More Efficient**
```javascript
function secondHighest(arr) {
  const max = Math.max(...arr);
  const filtered = arr.filter(num => num !== max);

  if (filtered.length === 0) return null;

  return Math.max(...filtered);
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## 3. **Single Loop Approach - Best Performance**
```javascript
function secondHighest(arr) {
  let max = -Infinity;
  let secondMax = -Infinity;

  for (let num of arr) {
    if (num > max) {
      secondMax = max;
      max = num;
    } else if (num > secondMax && num !== max) {
      secondMax = num;
    }
  }

  return secondMax === -Infinity ? null : secondMax;
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## 4. **Handles Duplicates Properly**
```javascript
function secondHighest(arr) {
  const unique = [...new Set(arr)];

  if (unique.length < 2) return null;

  unique.sort((a, b) => b - a);
  return unique[1];
}

console.log(secondHighest([11, 2, 31, 7, 15]));      // Output: 15
console.log(secondHighest([31, 31, 15, 11, 2]));    // Output: 15
console.log(secondHighest([5]));                     // Output: null
```

## Performance Comparison

| Approach | Time Complexity | Space Complexity | Best Use Case |
|----------|-----------------|------------------|---|
| Sort | O(n log n) | O(n) | Small arrays, readable code |
| Math.max filter | O(2n) | O(n) | Simple cases |
| Single loop | **O(n)** | **O(1)** | **Large arrays** |
| With Set | O(n log n) | O(n) | Duplicates matter |

**Recommendation:** Use the **single loop approach (#3)** for best performance with large datasets, or approach **#1** for clarity and simplicity.

# Second Highest Number Function

Here are several ways to solve this problem:

## Method 1: Using Sort (Simplest)
```javascript
function secondHighest(arr) {
  const sorted = [...arr].sort((a, b) => b - a);
  return sorted[1];
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Method 2: Using Set (Handles Duplicates)
```javascript
function secondHighest(arr) {
  const unique = [...new Set(arr)].sort((a, b) => b - a);
  return unique.length > 1 ? unique[1] : null;
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
console.log(secondHighest([5, 5, 5])); // Output: null
```

## Method 3: Single Loop (Most Efficient - O(n))
```javascript
function secondHighest(arr) {
  if (arr.length < 2) return null;

  let highest = -Infinity;
  let secondMax = -Infinity;

  for (let num of arr) {
    if (num > highest) {
      secondMax = highest;
      highest = num;
    } else if (num > secondMax && num < highest) {
      secondMax = num;
    }
  }

  return secondMax === -Infinity ? null : secondMax;
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## Method 4: Using Math.max (Clean & Readable)
```javascript
function secondHighest(arr) {
  const highest = Math.max(...arr);
  return Math.max(...arr.filter(num => num !== highest));
}

console.log(secondHighest([11, 2, 31, 7, 15])); // Output: 15
```

---

## Comparison

| Method | Pros | Cons |
|--------|------|------|
| **Sort** | Simple, readable | O(n log n) time complexity |
| **Set** | Handles duplicates | Slightly more code |
| **Loop** | Most efficient O(n) | More verbose |
| **Math.max** | Clean syntax | Creates extra arrays |

## Recommendation
- **For most cases**: Use **Method 1** (simple and readable)
- **For large arrays**: Use **Method 3** (best performance)
- **For duplicates**: Use **Method 2** (ignores duplicate values)

# Find Second Highest Number in JavaScript

Here are several ways to solve this:

## 1. **Using Sort Method (Simplest)**
```javascript
function findSecondHighest(arr) {
  const uniqueNumbers = [...new Set(arr)].sort((a, b) => b - a);
  return uniqueNumbers[1];
}

console.log(findSecondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## 2. **Using Two Variables (Most Efficient)**
```javascript
function findSecondHighest(arr) {
  let highest = -Infinity;
  let secondHighest = -Infinity;

  for (let num of arr) {
    if (num > highest) {
      secondHighest = highest;
      highest = num;
    } else if (num > secondHighest && num !== highest) {
      secondHighest = num;
    }
  }

  return secondHighest === -Infinity ? null : secondHighest;
}

console.log(findSecondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## 3. **Using Reduce Method**
```javascript
function findSecondHighest(arr) {
  const [highest, secondHighest] = arr.reduce(
    ([max, secondMax], num) => {
      if (num > max) {
        return [num, max];
      } else if (num > secondMax && num !== max) {
        return [max, num];
      }
      return [max, secondMax];
    },
    [-Infinity, -Infinity]
  );

  return secondHighest === -Infinity ? null : secondHighest;
}

console.log(findSecondHighest([11, 2, 31, 7, 15])); // Output: 15
```

## 4. **Handle Duplicates (Only Unique Values)**
```javascript
function findSecondHighest(arr) {
  const unique = [...new Set(arr)];

  if (unique.length < 2) return null;

  unique.sort((a, b) => b - a);
  return unique[1];
}

console.log(findSecondHighest([11, 2, 31, 31, 7, 15])); // Output: 15
```

## Comparison

| Method | Time | Space | Best For |
|--------|------|-------|----------|
| Sort | O(n log n) | O(n) | Small arrays, simplicity |
| Two Variables | O(n) | O(1) | **Large arrays, efficiency** |
| Reduce | O(n) | O(1) | Functional programming |
| Unique + Sort | O(n log n) | O(n) | Handling duplicates |

**Recommendation:** Use **Method 2** (Two Variables) for optimal performance with large datasets.
